import React, { useState } from "react";
import {
  GoogleMap,
  LoadScript,
  DirectionsService,
  DirectionsRenderer
} from "@react-google-maps/api";

const containerStyle = {
  width: "100%",
  height: "500px"
};

const center = {
  lat: 28.6139,
  lng: 77.2090
};

function GoogleMapView({ origin, destination }) {

  const [directions, setDirections] = useState(null);

  const directionsCallback = (response) => {

    if (response !== null) {

      if (response.status === "OK") {

        setDirections(response);

      }

    }

  };

  return (

    <LoadScript googleMapsApiKey="AIzaSyXXXXXXXXXXXX">

      <GoogleMap
        mapContainerStyle={containerStyle}
        center={center}
        zoom={12}

      >

        {origin && destination && (

          <DirectionsService
            options={{
              origin: origin,
              destination: destination,
              travelMode: "DRIVING"
            }}
            callback={directionsCallback}
          />

        )}

        {directions && (

          <DirectionsRenderer
            options={{
              directions: directions
            }}
          />

        )}

      </GoogleMap>

    </LoadScript>

  );

}

export default GoogleMapView;
